    val INF = 1_000_000_000_000_000_000L // Sufficiently large infinity

    // Cost2[i][j] = shortest path cost from i to j using only Type 2 moves
    val cost2 = Array(n) { LongArray(n) { INF } }

    // Build adjacency list for Cost2 graph
    val adj2 = Array(n) { mutableListOf<Int>() }
    for (i in 0 until n) {
        val c = closest[i]
        adj2[i].add(c)
        adj2[c].add(i)
    }

    // Run BFS from every node i
    for (startNode in 0 until n) {
        cost2[startNode][startNode] = 0L
        val queue = java.util.LinkedList<Int>()
        queue.add(startNode)
        val dist = IntArray(n) { -1 }
        dist[startNode] = 0

        while (queue.isNotEmpty()) {
            val u = queue.poll()
            for (v in adj2[u]) {
                if (dist[v] == -1) {
                    dist[v] = dist[u] + 1
                    cost2[startNode][v] = dist[v].toLong()
                    queue.add(v)
                }
            }
        }
    }


    val ans = LongArray(queries.size)
    for (i in queries.indices) {
        val l = queries[i][0].toInt()
        val r = queries[i][1].toInt()

        var minCost = abs(nums[l] - nums[r]) // Option 1: Direct jump

        // Option 2: L -> X (Type 2) -> R (Type 1)
        for (x in 0 until n) {
            if (cost2[l][x] != INF) {
                val cost = cost2[l][x] + abs(nums[x] - nums[r])
                if (cost < minCost) {
